use tokio::task::JoinHandle;
use std::time::Duration;

async fn simulate_computation(id: u32, delay: Duration) -> u32 {
    tokio::time::sleep(delay).await;
    println!("Computation {} finished.", id);
    id * 10
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let handles: Vec<JoinHandle<u32>> = vec![ 
        tokio::spawn(simulate_computation(1, Duration::from_millis(500))), 
        tokio::spawn(simulate_computation(2, Duration::from_millis(100))), 
        tokio::spawn(simulate_computation(3, Duration::from_millis(800))), 
    ].into_iter().collect();

    let mut results: Vec<u32> = Vec::new();

    for handle in handles { 
        match handle.await {
            Ok(result) => results.push(result),
            Err(e) => eprintln!("A task failed to join: {}", e),
        }
    }

    println!("nAll computations completed. Results received: {:?}", results);
    Ok(())
}

use std::time::{Duration, Instant};

struct SensorState {
    data_ready_mask: u32,
    timeout_duration: Duration,
}

impl SensorState {
    fn new() -> Self {
        SensorState {
            data_ready_mask: 0x10,
            timeout_duration: Duration::from_millis(50),
        }
    }

    fn poll_for_data(&self) -> Result<u32, &'static str> {
        let start_time = Instant::now();
        loop {
            if self.check_hardware_register() & self.data_ready_mask != 0 {
                return Ok(self.read_sensor_value());
            }

            if start_time.elapsed() > self.timeout_duration {
                return Err("Timeout waiting for data readiness bit.");
            }

            std::thread::sleep(Duration::from_millis(1));
        }
    }

    fn check_hardware_register(&self) -> u32 {
        0xAA
    }

    fn read_sensor_value(&self) -> u32 {
        0xBB
    }
}

fn main() {
    let sensor = SensorState::new();
    match sensor.poll_for_data() {
        Ok(data) => println!("Successfully read data: 0x{:X}", data),
        Err(e) => eprintln!("Error polling sensor: {}", e),
    }
}

use std::io::{Error, Result};
use std::time::Duration;
use tokio::time::sleep;
use futures::future::{self, TryFutureExt};

struct SensorReading {
    button_ok: bool,
    wifi_data: String,
    battery_level: u8,
}

async fn check_button() -> Result<bool> {
    println!("Checking button...");
    sleep(Duration::from_millis(50)).await;
    Ok(true)
}

async fn get_wifi_data() -> Result<String> {
    println!("Getting Wi-Fi data...");
    sleep(Duration::from_millis(100)).await;
    Ok("DataChunkA".to_string())
}

async fn read_battery() -> Result<u8> {
    println!("Reading battery...");
    sleep(Duration::from_millis(20)).await;
    Ok(95)
}

#[tokio::main]
async fn main() -> Result<()> {
    let button_fut = check_button();
    let wifi_fut = get_wifi_data();
    let battery_fut = read_battery();

    println!("Starting concurrent polling cycle.");

    let results = future::join3(button_fut, wifi_fut, battery_fut).await;

    let button_result = &results.0;
    let wifi_result = &results.1;
    let battery_result = &results.2;

    if let (Ok(button), Ok(wifi), Ok(battery)) = (button_result, wifi_result, battery_result) {
        println!("n--- Cycle Complete ---");
        println!("Button Status: {}", button);
        println!("WiFi Data Received: {}", wifi);
        println!("Battery Level: {}%", battery);
    } else {
        eprintln!("An error occurred during polling.");
    }

    Ok(())
}
